import { ChangeDetectorRef, Component, OnInit, ViewChild } from "@angular/core";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { IonInput } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
import { pagingService } from "src/app/core/services/paging.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { VendorService } from "src/app/core/services/vendor.service";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { Item } from "src/app/views/Models/Types/item.model";
import { Category } from "src/app/views/Models/Vendor/category";
import {
  AddItem,
  DeleteItem,
  EditItem,
  ItemInfo,
} from "src/app/views/Models/Vendor/item";

@Component({
  selector: "app-manage-items",
  templateUrl: "./manage-items.page.html",
  styleUrls: ["./manage-items.page.scss"],
})
export class ManageItemsPage implements OnInit {
  @ViewChild("searchItemInput") searchItemInput: IonInput;

  //#region Flags
  showLoader: boolean = false;
  showCategoryPath: boolean = false;
  showCategories: boolean = false;
  showItems: boolean = false;
  showAddItemModal: boolean = false;
  showEditItemModal: boolean = false;
  //#endregion Flags
  //#region Variables
  categories: Category[];
  selectedCategory: Category;
  filteredCategories: Category[];
  categoryRef: Item[];
  flatCategories: Category[];
  categoryPath: Category[];
  page: number = 1;
  itemList: ItemInfo[];
  resultCount: number = 0;
  searchTerm: string = "";
  searchItemTerm: string = "";
  savedSearchTerm: string = "";
  itemPage: number = 1;
  namingRef: StaticRef[];
  //#endregion
  //#region Forms
  itemForm: FormGroup = this.formbuilder.group({
    itemCode: [null],
    itemName: ["", [Validators.required, this.noWhitespaceValidator]],
    itemDesc: [""],
    itemExtCode: [""],
    catCode: [null],
    activeRec: [1],
    uuc: [""],
    defaultPrice: [0],
  });
  //#endregion

  constructor(
    public vendorService: VendorService,
    public alertService: AlertService,
    public formbuilder: FormBuilder,
    public pagingService: pagingService,
    private cdref: ChangeDetectorRef,
    private referenceService: ReferencesService,
    public inputMaskingService: InputMaskingService
  ) {}

  noWhitespaceValidator(control: FormControl) {
    const isWhitespace = (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }

  async ngOnInit() {
    this.showLoader = true;
    this.showCategories = true;
    this.namingRef = await this.referenceService
      .getCategoriesItemsRef()
      .toPromise();
    this.categories = await this.vendorService.getCategories();
    this.flatCategories = (function flattenAndFilter(
      cats: Category[]
    ): Category[] {
      return cats
        .map((cat) => {
          const children = cat.subCategories?.length
            ? flattenAndFilter(cat.subCategories)
            : [];
          return [cat, ...children];
        })
        .reduce((acc, val) => acc.concat(val), [])
        .filter((cat) => cat.leafCat);
    })(this.categories);
    this.categoryRef = this.flatCategories.map((cat) => {
      return {
        text: cat.catName,
        value: cat.catCode.toString(),
      };
    });
    this.filteredCategories = this.flatCategories;
    this.showLoader = false;
  }
  ngAfterContentChecked(): void {
    this.cdref.detectChanges();
  }
  search($event: Event) {
    const input = $event.target as HTMLInputElement;
    this.searchTerm = input.value;
    this.page = 1;

    this.filteredCategories = this.flatCategories.filter(
      (v) =>
        this.searchTerm == "" ||
        v.catName.toLowerCase().match(this.searchTerm.toLowerCase())
    );
  }
  changePage(newPage: number): void {
    this.page = newPage;
  }

  getCategoryPathArray(
    categories: Category[],
    targetCatCode: number
  ): Category[] | null {
    for (const category of categories) {
      if (category.catCode === targetCatCode) {
        return [category];
      }

      if (category.subCategories?.length) {
        const subPath = this.getCategoryPathArray(
          category.subCategories,
          targetCatCode
        );
        if (subPath) {
          return [category, ...subPath];
        }
      }
    }

    return null;
  }

  getCategoryPath(cat: Category) {
    this.showLoader = true;
    this.showCategoryPath = true;
    this.categoryPath = this.getCategoryPathArray(
      this.categories,
      cat.catCode
    ) as Category[];
    this.showLoader = false;
  }
  closeCategoryPathModal() {
    this.showCategoryPath = false;
    this.categoryPath = [];
  }

  async getItems(cat: Category) {
    this.showLoader = true;
    this.selectedCategory = cat;
    await this.vendorService
      .getItems(cat.catCode, this.searchItemTerm, this.itemPage)
      .toPromise()
      .then((res) => {
        this.showItems = true;
        this.resultCount = res.count;
        this.showCategories = false;
        this.itemList = res["result"];
        this.categoryPath = this.getCategoryPathArray(
          this.categories,
          cat.catCode
        );
        this.showLoader = false;
      });
  }

  async searchItems() {
    this.showLoader = true;
    this.searchItemTerm = this.searchItemInput.value.toString();
    if (this.savedSearchTerm != this.searchItemTerm) this.itemPage = 1;
    await this.vendorService
      .getItems(
        this.selectedCategory.catCode,
        this.searchItemTerm,
        this.itemPage
      )
      .toPromise()
      .then((res) => {
        this.savedSearchTerm = this.searchItemTerm;
        this.resultCount = res.count;
        this.itemList = res["result"];
        this.showLoader = false;
      });
  }

  backToCategories() {
    this.showLoader = true;
    this.showCategories = true;
    this.showItems = false;
    this.selectedCategory = null;
    this.searchItemTerm = "";
    this.searchItemInput.value = "";
    this.savedSearchTerm = "";
    this.itemPage = 1;
    this.resultCount = 0;
    this.itemList = [];
    this.showLoader = false;
  }

  changePaginationPage = async (newPage: number) => {
    this.itemPage = newPage;
    this.getItems(this.selectedCategory);
  };

  async deleteItem(item: ItemInfo) {
    if (
      await this.alertService.SaveAlert(
        "هل أنت متأكد من حذف هذا ال" + this.getNamingRefValue("4") + "؟"
      )
    ) {
      this.showLoader = true;
      let deleteItem: DeleteItem = {
        itemCode: item.itemCode,
        uuc: item.uuc.toString(),
      };
      await this.vendorService
        .deleteItem(deleteItem)
        .then(async () => {
          await this.getItems(this.selectedCategory);
          await this.alertService.showAlertConfirm("تمت الحذف بنجاح", false);
        })
        .catch(async (err) => {
          await this.alertService.showAlertError(err.error, false);
        });
      this.showLoader = false;
    }
  }
  openEditItemModal(item: ItemInfo) {
    this.itemForm.patchValue({
      itemCode: item.itemCode,
      itemName: item.itemName,
      itemDesc: item.itemDesc,
      itemExtCode: item.itemExtCode,
      catCode: item.catCode,
      activeRec: item.activeRec === 1 ? true : false,
      uuc: item.uuc,
      defaultPrice: item.defaultPrice.toString(),
    });
    this.showEditItemModal = true;
  }
  openAddItemModal() {
    this.itemForm.reset();
    this.itemForm.patchValue({
      catCode: this.selectedCategory.catCode,
      activeRec: true,
      defaultPrice: 0,
    });
    this.showAddItemModal = true;
    this.showEditItemModal = false;
  }

  async addItem() {
    this.showLoader = true;
    if (!this.itemForm.valid) {
      this.alertService.showAlertError(
        "يجب ادخال اسم ال" + this.getNamingRefValue("4"),
        false
      );
      this.showLoader = false;
      return;
    } else {
      let newItem: AddItem = {
        itemName: this.itemForm.value.itemName,
        itemDesc: this.itemForm.value.itemDesc,
        itemExtCode: this.itemForm.value.itemExtCode,
        catCode: this.itemForm.value.catCode,
        activeRec: this.itemForm.value.activeRec === true ? 1 : 0,
        defaultPrice: this.itemForm.value.defaultPrice
          ? this.itemForm.value.defaultPrice
          : 0,
      };
      await this.vendorService
        .addItem(newItem)
        .then(async () => {
          this.showAddItemModal = false;
          this.itemForm.reset();
          await this.getItems(this.selectedCategory);
          this.alertService.showAlertConfirm("تمت الاضافة بنجاح", false);
        })
        .catch((err) => {
          this.alertService.showAlertError(err.error, false);
        });
      this.showLoader = false;
    }
  }

  async editItem() {
    this.showLoader = true;
    if (!this.itemForm.valid) {
      this.alertService.showAlertError(
        "يجب ادخال اسم ال" + this.getNamingRefValue("4"),
        false
      );
      this.showLoader = false;
      return;
    } else {
      let editItem: EditItem = {
        itemCode: this.itemForm.value.itemCode,
        itemName: this.itemForm.value.itemName,
        itemDesc: this.itemForm.value.itemDesc,
        itemExtCode: this.itemForm.value.itemExtCode,
        catCode: this.itemForm.value.catCode,
        activeRec: this.itemForm.value.activeRec === true ? 1 : 0,
        uuc: this.itemForm.value.uuc.toString(),
        defaultPrice: this.itemForm.value.defaultPrice
          ? this.itemForm.value.defaultPrice
          : 0,
      };
      await this.vendorService
        .editItem(editItem)
        .then(async () => {
          this.showEditItemModal = false;
          this.itemForm.reset();
          await this.getItems(this.selectedCategory);
          this.alertService.showAlertConfirm("تمت التعديل بنجاح", false);
        })
        .catch((err) => {
          this.alertService.showAlertError(err.error, false);
        });
      this.showLoader = false;
    }
  }

  closeModal() {
    this.showAddItemModal = false;
    this.showEditItemModal = false;
    this.itemForm.reset();
  }

  getNamingRefValue(code: string): string {
    const ref = this.namingRef?.find((ref) => ref.ref_code === code);
    return ref?.ref_desc ?? "";
  }
}
